import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { API_URL } from '../config';

const Register = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [msg, setMsg] = useState({ type: '', text: '' });
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setMsg({ type: '', text: '' });
    try {
      const res = await fetch(`${API_URL}/api/auth/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
      });
      const data = await res.json();
      if (res.ok) {
        setMsg({ type: 'success', text: '账号创建成功！正在跳转登录...' });
        setTimeout(() => navigate('/login'), 1500);
      } else {
        setMsg({ type: 'error', text: data.msg === 'User already exists' ? '该用户名已被使用。' : data.msg });
      }
    } catch (err) {
      console.error(err);
      setMsg({ type: 'error', text: '服务器错误，请稍后再试。' });
    }
  };

  return (
    <div className="form-container">
      <h2>创建你的账号</h2>
      {msg.text && (
        <div style={{ color: msg.type === 'error' ? '#e30000' : '#0071e3', marginBottom: '15px', fontSize: '14px', fontWeight: 500 }}>
          {msg.text}
        </div>
      )}
      <form onSubmit={handleSubmit}>
        <input type="text" placeholder="Apple ID (用户名)" value={username} onChange={(e) => setUsername(e.target.value)} required />
        <input type="password" placeholder="密码" value={password} onChange={(e) => setPassword(e.target.value)} required />
        <button type="submit">注册账号</button>
      </form>
      <p>已经有账号了？ <a href="/login">在此登录。</a></p>
    </div>
  );
};

export default Register;
